<template><app-content class="h-panel payroll-page"><div class="h-panel-bar"><span class="h-panel-title">工资发放</span></div><div class="margin-top margin-left payroll-toolbar"><Button @click="loadList">刷新</Button></div><div class="h-panel-body"><Table :datas="datas" :border="true"><TableItem title="工资表" prop="sheetName"></TableItem><TableItem title="期间" prop="sheetNo"></TableItem><TableItem title="应发" prop="grossAmount"></TableItem><TableItem title="扣款" prop="deductionAmount"></TableItem><TableItem title="实发" prop="netAmount"></TableItem><TableItem title="状态" prop="status"></TableItem><TableItem title="操作" :width="180" align="center"><div class="actions" slot-scope="{data}"><span v-if="data.status!=='AUDITED'" @click="audit(data)">审核发放</span><span v-if="data.status==='AUDITED'&&!data.voucherId" @click="cancelAudit(data)">反审核</span></div></TableItem></Table></div></app-content></template>
<script>import payroll from '../../api/payroll'; export default { name: 'PayrollPayment', data() { return {datas: []} }, methods: { loadList() { payroll.sheet.list().then(({data}) => this.datas = data || []) }, audit(row) { payroll.sheet.audit(row.id).then(() => this.loadList()) }, cancelAudit(row) { payroll.sheet.cancelAudit(row.id).then(() => this.loadList()) } }, mounted() { this.loadList() } }</script>
<style scoped>.actions span{margin:0 5px;color:#3788ee;cursor:pointer}</style>
